                ..button::Style::default()
            };
            match status {
                Status::Active => base,
                Status::Hovered => {
                    let peach = theme.extended_palette().primary.weak.color;
                    base.background = Some(
                        if self.0 {
                            peach
                        } else {
                            theme.extended_palette().background.strong.color
                        }
                        .into(),
                    );
                    base
                }
                _ => base,
            }
        })
    }
