{{ $sshKey := "id_rsa" }}
{{ $encryptedKey := "id_rsa.age" }}

# Check if the decrypted key is already added
if ! ssh-add -l | grep -q "$(ssh-keygen -lf ~/.ssh/{{ $sshKey }} | awk '{print $2}')"; then
    echo "Decrypting SSH key and adding it to the agent..."

    # Decrypt the SSH key using age
    if [[ -f ~/.ssh/{{ $encryptedKey }} ]]; then
        age -d ~/.ssh/{{ $encryptedKey }} > ~/.ssh/{{ $sshKey }}
        chmod 600 ~/.ssh/{{ $sshKey }}
        ssh-add ~/.ssh/{{ $sshKey }}
        echo "SSH key added to the agent."
    else
        echo "Encrypted SSH key not found: ~/.ssh/{{ $encryptedKey }}"
    fi
else
    echo "SSH key is already added to the agent."
fi
{{- end }}

